var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"첫 번째 공세는 실패! 이미 두 명이나 리타이어 당한 카나리아 스쿼드─!","JPN":"最初の攻撃は失敗！　すでに二人もリタイアしてしまったカナリア・スクワッド─！","ENG":"First attack ended in failure! And Canary Squad has already lost 2 of their members!","TWN":"第一次進攻失敗！金絲雀小隊已經有二個人遭到淘汰—！"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"노엘의 분전으로 꽁무니는 뺐지만, 챔피언은 쉽게 도주를 허용하지 않는다구!","JPN":"ノエルが奮闘したおかげで逃げられましたが、チャンピオンはそう簡単に逃がしてくれないぞ！","ENG":"They were able to flee thanks to Noelle's sacrifice, but the champion isn't allowing them to escape so easily!","TWN":"在洛艾兒的奮戰之下，雖然得以脫身，但冠軍不會輕易容許他們逃掉的！"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"연이어 터지는 피격 판정! 앞으로 수차례면 격추 판정까지 다다르는 상황!","JPN":"どんどん溜まっていくダメージ判定！　あと数回溜まれば撃墜判定になっちゃう！","ENG":"Canary's aircraft is on its last wings! Just a few more hits, and it'll be determined as shot down!","TWN":"接連被判定為擊中！再來幾次的話，就會達到擊落判定！"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그렇다고 경기 구역을 이탈하면 즉시 패배 판정이니까 조심해야 할 걸?","JPN":"でも、試合エリアを離れてしまったらその場で負けになるから、気を付けないとね？","ENG":"But be careful not to go out of bounds or it'll be immediate defeat!","TWN":"但如果因此脫離賽區，就會立刻被判定失敗，所以要小心囉？"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드! 절체절명의 위기!","JPN":"カナリア・スクワッド！　絶体絶命の危機！","ENG":"Canary Squad's in a moment of crisis!","TWN":"金絲雀小隊！千鈞一髮的危機！"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 어떻게 여기까지 왔는데! 쉽게 포기하면 안 되지!","JPN":"しかしやっとここまで来たのに、諦めるわけにはいかないよね！","ENG":"But they made it so far! You can't give up that easily!","TWN":"但好不容易走到這一步！不能輕言放棄！"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"제한 시간까지 아직 한 번 더 역전할 찬스가 남아 있어!","JPN":"制限時間まであともう一回だけ逆転するチャンスはある！","ENG":"There's still enough time to make a turnaround!","TWN":"在比賽結束前還有一次可以反敗為勝的機會！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"마지막까지 최선을 다해! 널 응원하는 사람들을 실망시킬 셈이냐?!","JPN":"最後まで全力を出し切って！　あなたを応援してくれる人たちをがっかりさせるんじゃないよ！","ENG":"Give it your best until the end! You can't disappoint all the fans cheering you on!","TWN":"要盡全力拚到最後！你是想讓為你加油的人失望嗎？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"격추 판정까지 앞으로 3회……!","JPN":"撃墜判定まであと3回……！","ENG":"3 more hits until the ship goes down!","TWN":"距離被判定為擊落還有3次……！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"위험해. 이대로 수송선에 탑승한 상태로 격추 판정이 뜨면, 우리 전원 리타이어라고.","JPN":"まずいわ。このまま輸送船に乗った状態で撃墜判定になったら、私たち全員がリタイアになっちゃう。","ENG":"This isn't looking good. If our ship goes down with all of us in it, we're all out.","TWN":"太危險了，要是在大家搭乘運輸機的狀態下被判定為擊落，那我們全部都會遭到淘汰的。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"펠리세트! 일단 적당한 엄폐물 뒤에 내려 줄게!","JPN":"フェリセット！　とりあえず適当に隠れられそうな場所に降ろすわよ！","ENG":"Félicette! I'll drop you off behind some cover for now!","TWN":"費莉塞特！我先把你放在可以掩護你的遮蔽物後面！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"듣고 있나, 펠리세트?","JPN":"聞こえるか、フェリセット？","ENG":"Can you hear me, Félicette?","TWN":"你有聽到嗎，費莉塞特？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"듣고 있어요, 코치.","JPN":"聞いています、コーチ。","ENG":"I'm listening, Coach.","TWN":"有聽到，教練。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"라이카 양과 로이 군은 어떤가?","JPN":"ライカ君とロイ君の調子はどうだ？","ENG":"How's Laika and Roy?","TWN":"萊卡和羅伊情況如何？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};